__kernel void extract_kernel(const long d_Ne,
                             __global float *d_I) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = bx * NUMBER_THREADS + tx;

    if ((long)ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / 255.0f);
    }
}

__kernel void prepare_kernel(const long d_Ne,
                             __global float *d_I,
                             __global float *d_sums,
                             __global float *d_sums2) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = bx * NUMBER_THREADS + tx;

    if ((long)ei < d_Ne) {
        float v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(const long d_Ne,
                            const long d_no,
                            const int d_mul,
                            __global float *d_sums,
                            __global float *d_sums2,
                            const int d_num_blocks) {
    (void)d_Ne;

    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int gdim = get_num_groups(0);

    int ei = bx * NUMBER_THREADS + tx;
    int nf = NUMBER_THREADS - (gdim * NUMBER_THREADS - d_no);
    int df = 0;

    __local float d_psum[NUMBER_THREADS];
    __local float d_psum2[NUMBER_THREADS];

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * d_mul];
        d_psum2[tx] = d_sums2[ei * d_mul];
    } else {
        d_psum[tx] = 0.0f;
        d_psum2[tx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (nf == NUMBER_THREADS) {
        for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
            if (((tx + 1) % i) == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
            }
            barrier(CLK_LOCAL_MEM_FENCE);
        }

        if (tx == (NUMBER_THREADS - 1)) {
            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
        }
    } else {
        if (bx != (gdim - 1)) {
            for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (((tx + 1) % i) == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (NUMBER_THREADS - 1)) {
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        } else {
            for (int i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (int i = 2; i <= df; i = 2 * i) {
                if (((tx + 1) % i) == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                barrier(CLK_LOCAL_MEM_FENCE);
            }

            if (tx == (df - 1)) {
                for (int i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }

                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        }
    }

    (void)d_num_blocks;
}

__kernel void srad_kernel(const float lambda,
                          const int Nr,
                          const int Nc,
                          const long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global float *d_dN,
                          __global float *d_dS,
                          __global float *d_dW,
                          __global float *d_dE,
                          const float q0sqr,
                          __global float *d_c,
                          __global float *d_I) {
    (void)lambda;
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = bx * NUMBER_THREADS + tx;

    if ((long)ei < Ne) {
        int row = ei / Nc;
        int col = ei % Nc;

        float Jc = d_I[ei];

        float dN = d_I[iN[row] * Nc + col] - Jc;
        float dS = d_I[iS[row] * Nc + col] - Jc;
        float dW = d_I[row * Nc + jW[col]] - Jc;
        float dE = d_I[row * Nc + jE[col]] - Jc;

        float G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        float L = (dN + dS + dW + dE) / Jc;

        float num = (0.5f * G2) - ((1.0f / 16.0f) * (L * L));
        float den = 1.0f + 0.25f * L;
        float qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        float c = 1.0f / (1.0f + den);

        if (c < 0.0f) c = 0.0f;
        else if (c > 1.0f) c = 1.0f;

        d_dN[ei] = dN;
        d_dS[ei] = dS;
        d_dW[ei] = dW;
        d_dE[ei] = dE;
        d_c[ei] = c;
    }

    (void)Nr;
}

__kernel void srad2_kernel(const float lambda,
                           const int Nr,
                           const int Nc,
                           const long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global float *d_dN,
                           __global float *d_dS,
                           __global float *d_dW,
                           __global float *d_dE,
                           __global float *d_c,
                           __global float *d_I) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = bx * NUMBER_THREADS + tx;

    if ((long)ei < Ne) {
        int row = ei / Nc;
        int col = ei % Nc;

        float cN = d_c[ei];
        float cS = d_c[iS[row] * Nc + col];
        float cW = d_c[ei];
        float cE = d_c[row * Nc + jE[col]];

        float D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];
        d_I[ei] = d_I[ei] + 0.25f * lambda * D;
    }

    (void)Nr;
    (void)iN;
    (void)jW;
}

__kernel void compress_kernel(const long d_Ne,
                              __global float *d_I) {
    int bx = get_group_id(0);
    int tx = get_local_id(0);
    int ei = bx * NUMBER_THREADS + tx;

    if ((long)ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }
}
